from typing import List, Optional
from pydantic import BaseModel, Field

class EvaluationResult(BaseModel):
    """
    Schema for the output of the Evaluation Agent.
    This represents the LLM's structured reasoning on how a candidate fits a specific job.
    """
    candidate_id: str = Field(..., description="Foreign key to the candidate profile")
    job_id: str = Field(..., description="Foreign key to the job profile")
    
    # Contextual sub-scores generated by LLM analysis against the specific job (0.0 to 1.0)
    skill_match_score: float = Field(0.0, ge=0.0, le=1.0, description="How well candidate skills match job requirements")
    experience_match_score: float = Field(0.0, ge=0.0, le=1.0, description="How well experience duration and domain matches")
    cultural_fit_score: float = Field(0.0, ge=0.0, le=1.0, description="Assessment of soft skills and implicit constraints")
    
    # Reasoning
    key_strengths: List[str] = Field(default_factory=list, description="Top reasons to hire")
    skill_gaps: List[str] = Field(default_factory=list, description="Missing required or nice-to-have skills")
    red_flags: List[str] = Field(default_factory=list, description="Any concerns or mismatches")
    
    # Summarized reasoning
    evaluation_summary: str = Field(..., description="A 2-3 sentence summary of the evaluation")
